package main

import (
    "crypto/tls"
    "crypto/x509"
    "errors"
    "net/http"
    "net/url"
    "time"
)

// Compliant: Default secure HTTPS client (hostname verification enabled)
func makeSecureHTTPSRequest(targetURL string) (*http.Response, error) {
    // Default http.Client has hostname verification enabled
    client := &http.Client{
        Timeout: 30 * time.Second,
        // No custom TLS config = secure defaults
    }

    return client.Get(targetURL)
}

// Compliant: Explicit hostname verification with custom TLS config
func makeRequestWithCustomTLS(targetURL string) (*http.Response, error) {
    parsedURL, err := url.Parse(targetURL)
    if err != nil {
        return nil, err
    }

    tr := &http.Transport{
        TLSClientConfig: &tls.Config{
            ServerName: parsedURL.Hostname(), // Explicitly set for verification
            MinVersion: tls.VersionTLS12,     // Ensure minimum TLS version
            // Hostname verification is enabled by default when ServerName is set
        },
    }

    client := &http.Client{
        Transport: tr,
        Timeout:   30 * time.Second,
    }

    return client.Get(targetURL)
}

// Compliant: Secure TLS connection with explicit hostname
func connectToHostSecurely(hostname string, port string) (*tls.Conn, error) {
    config := &tls.Config{
        ServerName: hostname, // Must match certificate
        MinVersion: tls.VersionTLS12,
        // Hostname verification happens automatically
    }

    address := hostname + ":" + port
    return tls.Dial("tcp", address, config)
}

// Compliant: Custom certificate verification with hostname check
func makeRequestWithCustomVerification(targetURL string, rootCAs *x509.CertPool) (*http.Response, error) {
    parsedURL, err := url.Parse(targetURL)
    if err != nil {
        return nil, err
    }

    tr := &http.Transport{
        TLSClientConfig: &tls.Config{
            ServerName: parsedURL.Hostname(),
            RootCAs:    rootCAs,
            VerifyPeerCertificate: func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
                // Custom verification that still includes hostname checking
                opts := x509.VerifyOptions{
                    Roots:         rootCAs,
                    DNSName:       parsedURL.Hostname(), // Critical: verify hostname
                    Intermediates: x509.NewCertPool(),
                }

                if len(verifiedChains) == 0 || len(verifiedChains[0]) == 0 {
                    return errors.New("no verified certificate chains")
                }

                cert := verifiedChains[0][0]
                _, err := cert.Verify(opts)
                return err
            },
        },
    }

    client := &http.Client{Transport: tr}
    return client.Get(targetURL)
}

// Compliant: Secure client factory
func createSecureHTTPClient(timeout time.Duration) *http.Client {
    return &http.Client{
        Timeout: timeout,
        Transport: &http.Transport{
            TLSClientConfig: &tls.Config{
                MinVersion: tls.VersionTLS12,
                CipherSuites: []uint16{
                    tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                    tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                    tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
                    tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
                },
                PreferServerCipherSuites: true,
                // Hostname verification is enabled by default
            },
            TLSHandshakeTimeout: 10 * time.Second,
        },
    }
}

// Compliant: Hostname validation utility
func validateHostnameMatch(hostname string, cert *x509.Certificate) error {
    // Use Go's built-in hostname verification
    return cert.VerifyHostname(hostname)
}

// Compliant: Multi-hostname support (for services with multiple valid names)
func makeRequestWithAlternativeNames(targetURL string, allowedHostnames []string) (*http.Response, error) {
    parsedURL, err := url.Parse(targetURL)
    if err != nil {
        return nil, err
    }

    // Verify the hostname is in our allowed list
    hostname := parsedURL.Hostname()
    allowed := false
    for _, allowedHost := range allowedHostnames {
        if hostname == allowedHost {
            allowed = true
            break
        }
    }

    if !allowed {
        return nil, errors.New("hostname not in allowed list")
    }

    tr := &http.Transport{
        TLSClientConfig: &tls.Config{
            ServerName: hostname, // Verify against actual hostname
            MinVersion: tls.VersionTLS12,
        },
    }

    client := &http.Client{Transport: tr}
    return client.Get(targetURL)
}
